"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { useRouter, useSearchParams } from "next/navigation";
import { useAuth } from "@/lib/AuthContext";
import { market as marketApi } from "@/lib/apiClient";

interface Listing {
    id: string;
    title: string;
    price: number;
    is_free: boolean;
    category: string;
    condition: string;
    status: string;
    seller_anon_id: string;
    is_own_listing: boolean;
    images: { url: string; order_index: number }[];
    created_at: string;
}

const CATEGORIES = ["all", "electronics", "furniture", "clothing", "books", "other"];
const CONDITIONS = ["all", "new", "like_new", "good", "fair", "poor"];
const CATEGORY_EMOJI: Record<string, string> = {
    electronics: "💻", furniture: "🛋️", clothing: "👕", books: "📚", other: "📦", all: "🛍️"
};

export default function MarketPage() {
    const { user, isLoadingAuth } = useAuth();
    const router = useRouter();
    const searchParams = useSearchParams();
    const [listings, setListings] = useState<Listing[]>([]);
    const [loading, setLoading] = useState(true);
    const [category, setCategory] = useState("all");
    const [showCreate, setShowCreate] = useState(false);
    const [creating, setCreating] = useState(false);
    const [form, setForm] = useState({ title: "", description: "", price: "", is_free: false, category: "other", condition: "good", pickup_location_tag: "" });
    const [formError, setFormError] = useState("");

    useEffect(() => {
        if (!isLoadingAuth && !user) router.replace("/login");
    }, [user, isLoadingAuth, router]);

    const fetchListings = () => {
        setLoading(true);
        marketApi.listListings({ category: category !== "all" ? category : undefined })
            .then((data: any) => setListings(data.listings ?? []))
            .catch(console.error)
            .finally(() => setLoading(false));
    };

    useEffect(() => { if (user) fetchListings(); }, [category, user]);

    const handleCreate = async () => {
        if (!form.title.trim()) { setFormError("Title is required"); return; }
        if (!form.is_free && !form.price) { setFormError("Price is required"); return; }
        setFormError(""); setCreating(true);
        try {
            await marketApi.createListing({
                title: form.title.trim(),
                description: form.description.trim() || undefined,
                price: form.is_free ? 0 : parseFloat(form.price),
                is_free: form.is_free,
                category: form.category,
                condition: form.condition,
                pickup_location_tag: form.pickup_location_tag.trim() || undefined,
            });
            setShowCreate(false);
            setForm({ title: "", description: "", price: "", is_free: false, category: "other", condition: "good", pickup_location_tag: "" });
            fetchListings();
        } catch (e: any) { setFormError(e.message); }
        finally { setCreating(false); }
    };

    return (
        <div className="min-h-screen bg-slate-50">
            {/* Top bar */}
            <div className="sticky top-0 z-40 bg-white/80 backdrop-blur-md border-b border-slate-100 shadow-sm">
                <div className="max-w-4xl mx-auto px-4 py-3 flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Link href="/feed" className="w-8 h-8 rounded-xl bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition-colors">←</Link>
                        <span className="font-black text-slate-900 text-sm">🛍️ Market</span>
                        <span className="text-xs bg-slate-100 text-slate-500 px-2 py-0.5 rounded-full">{user?.school_id ?? "ETHZ"}</span>
                    </div>
                    <div className="flex items-center gap-2">
                        <Link href="/market/inbox" className="w-8 h-8 rounded-xl bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition-colors text-slate-500">💬</Link>
                        <button onClick={() => setShowCreate(true)} className="bg-blue-500 hover:bg-blue-400 text-white text-xs font-bold px-3 py-2 rounded-xl transition-all">+ Sell</button>
                    </div>
                </div>
            </div>

            {/* Category filter */}
            <div className="sticky top-[57px] z-30 bg-white/70 backdrop-blur-md border-b border-slate-100">
                <div className="max-w-4xl mx-auto px-4 py-2 flex gap-2 overflow-x-auto no-scrollbar">
                    {CATEGORIES.map((c) => (
                        <button
                            key={c}
                            onClick={() => setCategory(c)}
                            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-xs font-semibold whitespace-nowrap transition-all ${category === c ? "bg-blue-500 text-white shadow-sm" : "bg-slate-100 text-slate-500 hover:bg-slate-200"}`}
                        >
                            {CATEGORY_EMOJI[c]} {c.charAt(0).toUpperCase() + c.slice(1).replace("_", " ")}
                        </button>
                    ))}
                </div>
            </div>

            {/* Grid */}
            <div className="max-w-4xl mx-auto px-4 py-4">
                {loading ? (
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                        {Array(6).fill(0).map((_, i) => (
                            <div key={i} className="bg-white rounded-2xl animate-pulse overflow-hidden border border-slate-100">
                                <div className="aspect-square bg-slate-100" />
                                <div className="p-3 space-y-2"><div className="h-3 bg-slate-100 rounded w-3/4" /><div className="h-3 bg-slate-100 rounded w-1/3" /></div>
                            </div>
                        ))}
                    </div>
                ) : listings.length === 0 ? (
                    <div className="text-center py-20">
                        <div className="text-5xl mb-4">🛍️</div>
                        <p className="text-slate-500 font-medium">No listings yet</p>
                        <button onClick={() => setShowCreate(true)} className="mt-4 bg-blue-500 text-white text-sm font-semibold px-5 py-2.5 rounded-xl">List an item</button>
                    </div>
                ) : (
                    <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                        {listings.map((l) => (
                            <div key={l.id} className="bg-white rounded-2xl overflow-hidden border border-slate-100 shadow-sm hover:shadow-md transition-shadow cursor-pointer group">
                                <div className="aspect-square bg-slate-100 overflow-hidden relative">
                                    {l.images.length > 0 ? (
                                        <img src={l.images[0].url} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300" alt={l.title} />
                                    ) : (
                                        <div className="w-full h-full flex items-center justify-center text-4xl">{CATEGORY_EMOJI[l.category] ?? "📦"}</div>
                                    )}
                                    {l.is_own_listing && (
                                        <div className="absolute top-2 right-2 bg-blue-500 text-white text-[10px] font-bold px-1.5 py-0.5 rounded-lg">Yours</div>
                                    )}
                                    {l.status !== "active" && (
                                        <div className="absolute inset-0 bg-black/50 flex items-center justify-center">
                                            <span className="text-white font-bold text-sm uppercase">{l.status}</span>
                                        </div>
                                    )}
                                </div>
                                <div className="p-3">
                                    <p className="font-bold text-slate-900 text-sm leading-tight truncate">{l.title}</p>
                                    <div className="flex items-center justify-between mt-1">
                                        <p className="font-black text-slate-800">{l.is_free ? <span className="text-green-600">Free</span> : `CHF ${l.price.toFixed(2)}`}</p>
                                        <span className="text-[10px] text-slate-400 bg-slate-50 px-1.5 py-0.5 rounded-lg font-medium">{l.condition.replace("_", " ")}</span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            {/* Create Modal */}
            {showCreate && (
                <div className="fixed inset-0 z-50 bg-black/50 backdrop-blur-sm flex items-end sm:items-center justify-center p-0 sm:p-4">
                    <div className="bg-white w-full sm:max-w-lg rounded-t-3xl sm:rounded-3xl max-h-[92vh] overflow-y-auto">
                        <div className="flex items-center justify-between p-5 border-b border-slate-100">
                            <h2 className="text-lg font-black text-slate-900">List an item</h2>
                            <button onClick={() => setShowCreate(false)} className="w-8 h-8 rounded-xl bg-slate-100 flex items-center justify-center hover:bg-slate-200 transition-colors">✕</button>
                        </div>
                        <div className="p-5 space-y-4">
                            <div>
                                <label className="block text-xs font-semibold text-slate-600 mb-1.5">Title *</label>
                                <input type="text" value={form.title} onChange={(e) => setForm((f) => ({ ...f, title: e.target.value }))} placeholder="What are you selling?" className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-400/50" />
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-600 mb-1.5">Description</label>
                                <textarea value={form.description} onChange={(e) => setForm((f) => ({ ...f, description: e.target.value }))} placeholder="Details, condition, size…" rows={3} className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-400/50 resize-none" />
                            </div>
                            <div className="flex gap-3">
                                <label className="flex items-center gap-2 cursor-pointer">
                                    <input type="checkbox" checked={form.is_free} onChange={(e) => setForm((f) => ({ ...f, is_free: e.target.checked }))} className="w-4 h-4 rounded" />
                                    <span className="text-sm font-medium text-slate-700">Free</span>
                                </label>
                                {!form.is_free && (
                                    <div className="flex-1">
                                        <input type="number" value={form.price} onChange={(e) => setForm((f) => ({ ...f, price: e.target.value }))} placeholder="CHF 0.00" step="0.01" min="0" className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400/50" />
                                    </div>
                                )}
                            </div>
                            <div className="grid grid-cols-2 gap-3">
                                <div>
                                    <label className="block text-xs font-semibold text-slate-600 mb-1.5">Category</label>
                                    <select value={form.category} onChange={(e) => setForm((f) => ({ ...f, category: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400/50 bg-white">
                                        {CATEGORIES.filter((c) => c !== "all").map((c) => <option key={c} value={c}>{c.charAt(0).toUpperCase() + c.slice(1).replace("_", " ")}</option>)}
                                    </select>
                                </div>
                                <div>
                                    <label className="block text-xs font-semibold text-slate-600 mb-1.5">Condition</label>
                                    <select value={form.condition} onChange={(e) => setForm((f) => ({ ...f, condition: e.target.value }))} className="w-full border border-slate-200 rounded-xl px-3 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-blue-400/50 bg-white">
                                        {CONDITIONS.filter((c) => c !== "all").map((c) => <option key={c} value={c}>{c.charAt(0).toUpperCase() + c.slice(1).replace("_", " ")}</option>)}
                                    </select>
                                </div>
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-slate-600 mb-1.5">Pickup location</label>
                                <input type="text" value={form.pickup_location_tag} onChange={(e) => setForm((f) => ({ ...f, pickup_location_tag: e.target.value }))} placeholder="e.g. HG Building, CAB" className="w-full border border-slate-200 rounded-xl px-4 py-2.5 text-sm placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-blue-400/50" />
                            </div>
                            {formError && <p className="text-red-500 text-sm bg-red-50 px-4 py-3 rounded-xl">{formError}</p>}
                            <button onClick={handleCreate} disabled={creating} className="w-full bg-blue-500 hover:bg-blue-400 disabled:opacity-50 text-white font-bold py-3 rounded-xl transition-all">
                                {creating ? "Listing…" : "Post Listing"}
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}
